INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04580', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某個被列為低收入戶的家庭，夫妻二人均有輕度身心障礙，且沒有穩定工作，並育有五名未成年 子女。近日，再度因疏忽照顧被通報脆弱家庭服務。經社會工作者了解，這個家庭除了政府補助 外，也有多個民間非營利組織與慈善團體提供各種津貼與物資。當社會工作者猶豫要不要向服務 對象提出結紮意見時，是處於何種倫理困境？', '["「社會團體責任」相對於「個人家庭責任」之衝突", "「強調過程」相對於「強調結果」之衝突", "「安全滿足」相對於「刻苦奮鬥」之衝突", "「文化決定」相對於「個人本能」之衝突"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04581', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何種形式，非屬長期照顧機構的高齡者常遭遇的不當對待？', '["打擾團體活動進行，被限制於房間內", "制式化規定飲食、沐浴、睡眠等，缺乏個人選擇", "案主出現自傷行為，依醫囑給予約束", "不配合日常照護，被工作人員視為「麻煩製造者」、「難照顧」，而被差別對待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04582', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '經濟安全一向是單親家庭的最大隱憂，尤其女性單親容易落入貧窮困境，形成貧窮女性化現象。 已有一些實證研究顯示，單親婦女創業時面臨的困境不少，下列何者不屬於常見困境？', '["托育資源不足", "社會環境限制", "單親婦女工作能力較低", "社會網絡支持不夠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04583', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作師在協助目睹家庭暴力的兒童時，必須因應兒童的需求扮演不同角色。下列何者非社會 工作師主要扮演的角色？', '["倡導者", "直接服務", "個案管理者", "監督者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04584', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關優勢觀點（strengthperspective）與增權取向（empowermentapproach）在社區層級系統推動青 少年工作的主張，下列何者錯誤？', '["將青少年視為社區的貢獻者", "創造機會讓青少年參與社區的規劃與行動", "強調成年人與青少年之間的合作夥伴關係", "成年人要避免成為導師角色（mentor）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04585', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有美國的學校社會工作者認為學生的問題非來自學生團體本身，而是與學校、社區有關，學校社 會工作者與其他專業組織組成多專業團體，提供學生個案、團體和方案合作，共同改善妨礙學習 的措施。這屬於下列何種模式？', '["學校變遷模式", "傳統臨床模式", "學校—社區—學童模式", "社區諮商模式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04586', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於無障礙設備設施之敘述，何者正確？', '["和合設計（InclusiveDesign）主張應將所有不同使用者的情況與需求考慮在內", "通用設計（UniversalDesign）強調透過設計來拓展人類經驗豐富性，讓使用者有更多的感官能 參與活動，或體驗多層次的經驗", "社會模式的設計主張將環境或輔具的設計交託給設計師或建築師做決定", "建構無障礙環境時，評估成本除了考慮所付出的代價外，還應考慮不採取行動時所要付出的代價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04587', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依消除對婦女一切形式歧視公約（CEDAW）各國應給男女在法律面前平等的地位，關於子女監 護、收養等類似制度，除男女有相同權利義務，均應以兒童的利益為重。社會工作者是協助法院 了解何種兒童照顧安排符合兒童利益。民法第 1055 條之 1 列出評估報告需特別注意事項，下列', '["子女年齡、性別、人數", "父母再婚機率", "祖父母態度", "族群習俗  ⑤父 母一方是否支持共親職  ⑥父母照顧意願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04588', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者是社會工作者預防職場歧視的有效方法？', '["推動公司成員參與多元文化教育訓練", "鼓勵公司成員舉發", "避免僱用少數族群與弱勢者", "避開勞動法規，訂定勞動契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04589', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是培養社會工作者文化勝任能力（culturalcompetence）的作法？', '["反身性的自我覺察", "開放性的了解文化差異", "加入宣稱文化普同性（universal）的倡議團體", "透過行動對其他文化群體表達尊重和接納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
